\label{propagation of chaos}
The assumptions of the following lemma still hold.
\begin{lemma}\label{weak solution}
\textup{(Existence of weak solution, \cite[Theorem 2, Lemma 16, and Lemma 18]{BOL2026113712})}.
Let $u_0\ge0$ be a initial probability density that satisfies
\begin{eqnarray*}
&u_0\log u_0\in L^1(\R^2), \quad \nabla\log u_0\in W^{1,q}(\R^2)~(q>2),\\
&u_0\in L^1(\R^2,|x|^2dx)\cap L^p(\R^2)~(1\le p\le \infty).   
\end{eqnarray*}
Furthermore, assume $\chi<4/c_*$, where $c_*$ is the optimal constant in the Gagliardo-Nirenberg inequality: $\|\omega\|_{L^4(\R^2)}^4\le c_*\|\omega\|_{L^2(\R^2)}^2\|\nabla\omega\|_{L^2(\R^2)}^2$. Then for any $T>0$ and $t\in[0,T]$, the problem \eqref{rpde} possesses weak solutions $(u^\varepsilon, v^\varepsilon)$ in $\R^2\times(0,T)$, and there exists a time $T^*\in(0,T)$ such that 
\begin{eqnarray}
&\|u^\varepsilon\|_{{L^2(0,T;H^1(\R^2))}\cap L^\infty(0,T;L^p(\R^2))}\le C,\label{uniformweaksolution}\\
&\||x|^2u^\varepsilon\|_{L^\infty(0, T; L^1(\R^2))}\le C,\quad\|\nabla\log u^\varepsilon\|_{L^\infty(0, T^*; W^{1,q}(\R^2))}\le C.\label{uniformweaksolution1}
\end{eqnarray}
where $C$ is a constant independent of $\varepsilon$. 
\end{lemma}
Let $\{X_{N,i}^\varepsilon\}_{1\le i\le N}$ and $\{\overline{X}_i^\varepsilon\}_{1\le i\le N}$ be the solutions to systems
\begin{align}\label{sde}
\begin{cases}
dX_{N,i}^\varepsilon(t) = \Big(2\exp\Big(-\frac{1}{N}\sum_{j=1}^N\Phi^\varepsilon(X_{N,i}^\varepsilon(t) - X_{N,j}^\varepsilon(t))\Big)+ 2\Big)^{1/2}dB_i(t),\\
X_{N,i}^\varepsilon(0) =\zeta_i,\qquad 1\le i\le N,
\end{cases}
\end{align}
and
\begin{align}\label{mfs}
\begin{cases}
d\overline{X}_i^\varepsilon(t) = \big(2\exp\big(-\Phi^\varepsilon * u^\varepsilon( \overline{X}_i^\varepsilon,t)\big)+2\big)^{1/2} dB_i(t),\\
\overline{X}_i^\varepsilon(0) = \zeta_i,\qquad 1\le i\le N,
\end{cases}
\end{align}
respectively. Then 
for any $m,N\in \mathbb{N}^+$ and parameters $0<\theta<\frac{1}{2},\quad 0<\alpha<\frac{\theta}{2},\quad m>\frac{\theta+1}{1-2\theta}$, there exist a constant $C(m,T)>0$ and a parameter $\gamma,\eta>0$ satisfying the bounds
\begin{align}
&0<\gamma<\min\big\{\frac{\alpha}{3},\frac{-2\alpha +m(1-2\theta)-1}{4m+4}\big\},\label{gamma} \\
&0<\eta\le\min\{\theta-2\alpha, -(4m+4)\gamma-2\alpha +m(1-2\theta)-1\}\label{eta}
\end{align}
such that for all $0\le t\le T$,
\begin{align}\label{Pe}
\mathbb{P}\big(\max_{i=1,\cdots,N}\big|(X_{N,i}^\varepsilon - \overline{X}_i^\varepsilon)(t)\big|> N^{-\alpha}\big)\le C(m,T)N^{-\eta}, 
\end{align}   
where the cut-off parameter satisfies
