    \end{cases}
\end{align}
and
\begin{align}\label{system_prelimit}
    \begin{cases}
        &\partial_t u^{\epsilon}=\nu A u^{\epsilon}-b(u^{\epsilon}+\epsilon^{-\alpha+\H}w^{\epsilon}+r^{\epsilon},u^{\epsilon}),\\
        &dw^{\epsilon}=\epsilon^{-1}Cw^{\epsilon} dt+ \epsilon^{-\H}dW^\H_t, \\
        &\begin{aligned}\partial_t r^{\epsilon}&=\epsilon^{-1}Cr^{\epsilon}+\nu A(\epsilon^{-\alpha+\H}w^{\epsilon}+r^{\epsilon})\\&-b(u^{\epsilon}+\epsilon^{-\alpha+\H}w^{\epsilon}+r^{\epsilon},\epsilon^{-\alpha+\H}w^{\epsilon}+r^{\epsilon}),
        \end{aligned}\\
        &w^{\epsilon}(0) =0,\quad r^{\epsilon}(0)=v_0^{\epsilon}.
