	\begin{cases}
		\partial_t \widetilde{\eta}=v,\\
		\partial_t v_{i} + \frac{2}{1+t} v_{i} + \frac{1}{(1+t)^{d(\gamma -1)+2}} a_{il}\partial_l q -\Delta \widetilde{\eta}_{i} =0,\\
		(v,\widetilde{\eta})|_{t=0} = \big(v_0, \widetilde{\eta}_0\big)
	\end{cases}
  \end{eqnarray}
).
\item Since the coefficients depend on $t$ ("the coefficients ... involves functions depending on $t$"), they do not use vector-field/space-time resonance methods; instead they "turn to the $t$-dependent damping effect of the velocity" and construct "different weights for unknowns ... in the form of $\mathcal{L}(t)$" and verify the differential inequality
\begin{equation}\label{est_L_1}
  \begin{split}
  \udt \mathcal{L}(t) + \frac{1}{1+t} \mathcal{L}(t)\le \frac{C}{(1+t)^{2}}\big(\mathcal{L}(t) + \mathcal{L}^{\frac{7}{2}}(t)\big).
  \end{split}
\end{equation}
\item Introduce "different temporal weights in a series of uniform estimates"; "the terms in $\mathcal{L}(t)$ in
\begin{equation}\label{L}
	\begin{split}
    \mathcal{L}(t) := &\|v(t)\|_{H^3}^2 + \frac{2}{(1+t)^2}\|\widetilde{\eta}(t)\|_{H^3}^2 + \|\nabla \widetilde{\eta}(t)\|_{H^3}^2+ \frac{2}{1+t}\sum_{i = 0}^{3} \langle\nabla^{i} v(t),\nabla^{i} \widetilde{\eta}(t)\rangle \\ &+ \frac{1}{\gamma(1+t)^{d(\gamma -1)+2}} \int_{\mathbb{R}^d}J^{\gamma+1}(t) |\nabla^3 q(t)|^2 \,dy.
	\end{split}
\end{equation}
carry distinct weights". "Thanks to the presence of the deformation gradient, which provides an effective diffusion mechanism, the temporal weights of all derivatives of all unknowns become uniform," and this "plays a key role in establishing the global well-posedness ... in both two and three dimensions". This yields global existence in Lagrangian variables; more precisely, they establish the following theorem.

\begin{theorem}\label{global_existence_Lagrangian}
       For $d=2,3$,  there exists a sufficiently small  constant $\varepsilon_1>0$ such that the Cauchy problem \eqref{compressible_elasticity_equation_3} admits a global strong solution 
       $(V,\xi)$ satisfying $(V(y,t)-y, \xi(y,t) - (1+t)y)$ in $C\big([0, \infty); H^3_y(\mathbb{R}^d)\times H^4_y(\mathbb{R}^d)\big)$,  provided that
          \begin{equation*} \label{initial_assumption_Lagrangian}
              \begin{split}
              \|V_0(y)-y\|_{H^3_y} + \|\xi_0(y) -y\|_{H^4_y}\le \varepsilon_1.
              \end{split}
          \end{equation*}
Moreover, $(V,\xi)$ satisfies the following estimates:
\begin{eqnarray}\label{decay_estimates_Lagrangian}
  \begin{cases}
    \|V(y,t) -y\|_{H^3_y} \le C\varepsilon_1(1+t)^{\frac{1}{2}},\\[1mm]
    \|\xi(y,t) - (1+t)y\|_{H^3_y} \le C\varepsilon_1(1+t)^{\frac{3}{2}},\\[1mm]
     \|\nabla_y \xi(y,t) - (1+t)I\|_{H^3_y} \le C\varepsilon_1(1+t)^{\frac{1}{2}}
  \end{cases}
\end{eqnarray}
for all $t>0$, where $C$ is a generic positive constant depending on some known constants but independent of $\varepsilon_1$ and $t$.
\end{theorem}

\item \emph{Transfer back to Eulerian coordinates} ("transferred back into the Eulerian coordinate as stated in the main theorem via the flow map"), and obtain the stated decay, noting that "in Eulerian coordinate each additional derivative accelerates decay by a factor of $(1+t)^{-1}$."
\end{itemize}

theorem:
\label{th:main} 
The trivariate statistic {\rm (}$\ides$, $\des$, $\maj${\rm )}  are equidistributed over  the set of $n$-Andr\'e I permutations,  $n$-Andr\'e II permutations and $n$-simsun permutations, i.e.,
   \begin{align*}
\sum_{\sigma \in \AndI_n} s^{\ides(\sigma)}t^{\des(\sigma)}  q^{\maj(\sigma)}
	&=\sum_{\sigma \in \AndII_n} s^{\ides(\sigma)}t^{\des(\sigma)}  q^{\maj(\sigma)}\\[5pt]
    &=\sum_{\sigma \in \RS_{n}} s^{\ides(\sigma)}t^{\des(\sigma)} q^{\maj(\sigma)}.
\end{align*}

sketch:
To prove the main theorem, we proceed as follows. First, by “sending Andr\'e permutations and simsun permutations to increasing binary trees” and applying the following proposition.

\begin{Proposition} \label{th:equi-shape-des} Let $\sigma$ be a permutation, and let $T_\sigma=\Psi(\sigma)$ be the increasing binary tree corresponding to $\sigma$ under the bijection $\Psi$. Then the descent set $\Des(\sigma)$ of $\sigma$ is completely determined by  the shape of $T_\sigma$.   
\end{Proposition}

Using this (as indicated in Section 2), the proof “reduces to showing that the inverse descents (ides) is equidistributed over the $n$-Andr\'e I permutations, the $n$-Andr\'e II permutations and the $n$-simsun permutations that share the same tree shape”, i.e. to proving the following theorem.

\begin{Theorem}\label{th:equi-shape} For $n\geq 1$ and any  unlabeled binary tree $T \in \URL_n$, we have  
  \begin{align}
 	 \sum_{\sigma \in \AndI(T)}   s^{\ides(\sigma)} \overset{(a)}{=}\sum_{\sigma \in \AndII(T)}  s^{\ides(\sigma)} \overset{(b)}{=}\sum_{\sigma \in \RS(T)}  s^{\ides(\sigma)}.
\end{align}
\end{Theorem}

The proof of this theorem is then split into two parts: (a) equidistribution of $\ides$ for $n$-Andr\'e I vs. $n$-Andr\'e II with the same tree shape (relation (a)), and (b) equidistribution of $\ides$ for $n$-Andr\'e II vs. $n$-simsun with the same tree shape (relation (b)). For (a), the sketch says the proof “relies on an investigation of the shuffle of permutations” (as indicated in Section 3); for (b), it “proceeds by constructing a bijection between the set of $n$-Andr\'e II permutations and the set of the $n$-simsun permutations” (as indicated in Section 4). This completes the proof of the main theorem.

theorem:
\label{thm:main_CM}
    The modular curve $X_0(N)$ has a sporadic CM point if and only if 
    \begin{align*}
        N\notin S_{CM}:=\{&1-13, 15-18, 20-26,30-33, 35-37,39-41, 46-50,\\
        &53,59 -61, 65,70-72,79,80,83,87,89,94,96, 101,131,144\}
    \end{align*},

sketch:
We split the proof of the main theorem by the least degree of a CM point on $X_0(N)$ (the proofs are given later). A key difficulty is that in CGPS22 certain cases were unresolved because the values of $\delta(X_0(N))$ were not known and available bounds were insufficient to decide whether CM points produce sporadic points. One tool used is to obtain new bounds on $\delta(X)$ using recent results of Kadets and Vogt KadetsVogt25 on low-degree points: for $\delta(X)=d$ to be relatively small, the curve must admit either a degree $d$ map to $\mathbb{P}^1$, or a map to an elliptic curve of positive rank, or a very small degree map to a curve of very small genus. We first record the precise statement used:

\begin{theorem}[{\cite[Theorem 1.3.]{KadetsVogt25}}]\label{thm:kv}
    Suppose $X/k$ is a nice curve of genus $g$ and $\delta(X)=d.$ Let $m:=\lceil d/2 \rceil-1 $ and let $\epsilon:=3d-1-6m$. Then one of the following holds:
    \begin{itemize}
        \item[(1)] There exists a nonconstant morphism of curves $\phi:X\rightarrow Y$ of degree at least 2 such that $d=\delta(Y/k)\cdot \deg \phi$;
        \item[(2)] The genus of $X$ is bounded by 
        $$g\leq \max \left( \frac{d(d-1)}2 +1, 3m(m-1)+m\epsilon \right).$$
    \end{itemize}
\end{theorem}

They then rule out maps of degree $d$ to elliptic curves of positive rank using methods of DerickxOrlic2024, and rule out degree $2$ maps from $X_0(N)$ to small genus curves by describing involutions of $X_0(N)$ in detail later.

A sketch of the proof of the main theorem (and Theorem~\ref{thm1.2}) is given and is divided into five parts:

$\langle i\rangle$ \emph{A New Minimax Framework.} The proofs are “structured around a novel minimax argument that incorporates the estimates of explicit lower bounds of the generalized Morse index directly into seeking for critical points of the energy functional.” The approach “differs fundamentally from the standard one for the proof of the mountain pass theorem,” aiming “to distinguish these critical points by estimating their generalized Morse indices,” since “standard minimax theories … are not suitable” here (lack of symmetry / topology).

$\langle ii\rangle$ \emph{Smoothing and Finite-Dimensional Approximation.} One “mollif[ies] the nonlinearity $f$ and obtain[s] smoothed functionals $J_m$,” and for fixed $m$ studies “critical points of $J_m$ restricted to finite-dimensional subspaces $X_n$,” i.e. $J_{m,n}$.

$\langle iii\rangle$ \emph{The Invariant Minimax Family and Smooth Flow.} A mapping family for $J_m$ is defined on an annulus $D_{r_k,R_k}$ in $X_k$ (with $k<n$) and is “invariant under the descending flow of $X_n$.” The key step is to establish “the $C^2$ smoothness of the flow $\tau(t,u)$” in the initial value $u\in X_n$. We first use the following lemma.

\begin{lemma}
\label{lem2.1} Assume $\left( g_1\right) $ holds, i.e., $g:X\rightarrow X$
is a $C^2$ mapping. Then the Cauchy problem
\begin{equation}
\left\{
\begin{array}{c}
\frac{d\tau \left( t,u\right) }{dt}=g\left( \tau \left( t,u\right) \right) ,\text{ }\left( t,u\right) \in \Bbb{R}^{+}\times X, \\
\tau \left( 0,u\right) =u\in X,
\end{array}
\right.  \label{eq5}
\end{equation}
has a unique solution $\tau \left( t,u\right) \in C^2\left( \Bbb{R}
^{+}\times X,X\right) $. Furthermore, the derivative with respect to the
initial value, which we denote by $\tau _u^{\prime }\left( t,u\right) $, as
a bounded linear operator from $X$ to $X$, is injective for all $t$, i.e., $
\ker \tau _u^{\prime }\left( t,u\right) =\left\{ 0\right\} $. Finally, for
each initial point $u\in X$, if $g\left( \tau \left( t,u\right) \right) =0$
and $g\left( u\right) \neq 0$, then $t=\infty $.
\end{lemma}

In view of this lemma, “the Gronwall-Bellman inequality first ensures the uniqueness of the flow,” and together with “the $C^2$ smoothness of the governing vector field” yields “the injectivity of its derivative and the flow’s $C^2$ smoothness in the initial data.” The family is realized as a restriction of the flow, and for each $t>0$ the flow gives a diffeomorphism from $D_{r_k,R_k}$ onto a $C^2$ submanifold $A_t\subset X_n$.

$\langle iv\rangle$ \emph{Critical Points with Index Bounds.} The associated minimax value $C_k^{(m,n)}$ is shown to be “a critical value of $J_m$ on $X_n$.” By studying maximum points $v_{t_j}$ on $A_{t_j}$ for $t_j\to\infty$, one obtains “a Palais-Smale sequence for $J_m$ on $X_n$.” Moreover, “the sum of the dimensions of the negative and zero subspaces of the Hessian $J_m''(v_{t_j})$ is at least $k$,” using “the triviality of the kernel of $\tau_u'(t,u):X_k\to T_{\tau(t,u)}A_t$,” i.e. using that $\ker \tau _u^{\prime }\left( t,u\right) =\left\{ 0\right\} $ from the lemma above. This yields a critical point $u_{m,n,k}$ with “generalized Morse index $M(J_{m,n},u_{m,n,k})\ge k$.”

$\langle v\rangle$ \emph{Limit Passage.} A “final two-step limit process, first as $m\to\infty$ and then as $n\to\infty$, employing the (PS)$^{**}$ … and (PS)$^{*}$ conditions respectively,” produces “a sequence of critical points $\{u_k\}_{k=1}^\infty$ for the functional $J$ satisfying $M(J,u_k)\ge k$, and thus completes the proof of the main theorems.”

At a conceptual level, the proof of the main theorem (and the following theorem) “follow the strategy of \cite{CM10} in the bounded-curvature regime”: when two embedded minimal sheets are “very close but disjoint,” their “separation function satisfies a uniformly elliptic equation whose coefficients are controlled by \(|A|\)”; then “a Harnack inequality” gives “quantitative control on how fast the sheets can separate.” We first prove the following theorem.

\begin{mainthm}\label{thm:unbounded}
Let \(\Sigma^{n} \subset \mathbb{R}^{n+1}\) be a complete, embedded minimal hypersurface and assume that \(\sup_{\Sigma}|A|^2 < \infty\). Then \(\Sigma\) is unbounded.
\end{mainthm}

theorem:
\label{T1}
 Let $f_{0} \in C^{1,\mu}_{0}\big(\bar{\Omega}\times\mathbb{R}^{2}\big), f_{0}\geq 0$ for some $0 <\mu< 1$, satisfying
\begin{align}
  f_{0}\in C^{1,\mu},\quad f_{0}(x,v)=\text{constant,\,\,  dist}((x,v), \Gamma)\leq \delta_{0},\label{v2.8}
\end{align}
Suppose that $h \in C^{2,\mu} (\partial\Omega)$ satisfies
\begin{align}
\int_{\Omega}f_{0}(x,v){\rm d}x{\rm d}v=\int_{\partial\Omega}h(x){\rm d}l, \label{v1.12}
\end{align}
and $h > 0$. Then there exists
a unique solution $f \in C^{1;1,\lambda}_{t;(x,v)} \big((0,\infty)\times \bar{\Omega}\times \mathbb{R}^{2}\big),
\varphi\in  C^{1;3,\lambda}_{t;x}\big((0,\infty)\times \bar{\Omega}\big) $
for
some $0 < \lambda < \mu$, of the relativistic Vlasov-Poisson system
\begin{align}
&\partial_t f+\hat{v}\cdot\nabla_{x}f+\nabla_{x}\varphi\cdot\nabla_{v}f=0, \label{v1.5}\\
&\Delta\varphi=\rho, \label{v1.6}
\end{align}
with compact support
in $x$ and $v$, where the  initial boundary conditions of $(f,\varphi)$ satisfy
\begin{align}
&f(0,x,v)=f_{0}(x,v),\quad x\in \Omega,\; v\in \mathbb{R}^{2}, \label{v1.8}\\
&f(t,x,v)=f(t,x,v^{*}),\quad x\in \partial\Omega, \; v\in \mathbb{R}^{2},\; t>0, \label{v1.9}
\end{align}
\begin{align}
 &f_{0}(x,v)\geq 0,  \label{v1.10}\\
 &v^{*}=v-2\big(n_{x}\cdot v\big)n_{x}, \quad (x,v)\in \partial\Omega \times \mathbb{R}^{2}, \label{v1.11}
 \end{align}
and
\begin{align}
   &\frac{\partial \varphi}{\partial n_{x}}=h(x),\,\,\, x\in \partial \Omega,\,t>0,\label{v1.7}
   \end{align}
respectively.

sketch:
To prove the main results (in particular the main theorem), the introduction describes the following strategy.

1. **Linearized well-posedness via a velocity lemma:** “we first apply the velocity lemma to establish the well-posedness of linearized problems.”

2. **Iterative construction and convergence:** “Then, we construct an iterative scheme and show the convergence of the iterative sequences.” The “main issues” in this step are “the uniform boundedness in a given function space and the prolongation of uniform estimates for the functions ${f^{n}}$.”

3. **Bootstrapping to final regularity/conclusion:** “Finally, we use bootstrapping techniques to reach the desired conclusions.”

4. **Control of boundary interactions / collisions (via adapted coordinates):** Near the singular set and boundary, the plan is to “draw on insights from previous research,” assuming “the initial data $f_{0}$ remains constant near the singular set,” and “to analyze the characteristic curves close to the boundary, we will use geometric methods.” For the (Neumann) boundary analysis, they “select coordinate variables $(\alpha,\beta)$,” where “$\alpha$ characterizes the distance from points on the characteristic curve to the singular set” and “$\beta$ … describes the number of collisions between particles and the boundary,” with the observation that “the number of collisions is inversely proportional to the distance to the singular set.” For this purpose (to ensure the collision number is uniformly bounded), they assume
\begin{align}
  f_{0}\in C^{1,\mu},\quad f_{0}(x,v)=\text{constant,\,\,  dist}((x,v), \Gamma)\leq \delta_{0},\label{v2.8}
\end{align}

5. **Paper roadmap matching the proof:** Sections 2–5 implement this plan: “introduce an iterative system … define a sequence of functions $\{ f^{n}\}$, the limit … is the desired global solution,” then “establish the well-posedness of the linear problem,” then “show … convergence … under the condition that $Q(t)$ is bounded,” and finally “prove the boundedness of the function $Q(t)$. This concludes the proof of the first theorem.”

theorem:
\label{thm:main}
Let $\mu$ be a translation-invariant, ergodic, finite-energy edge percolation measure on $\mathbb{Z}^2$.  Then one of the following holds:
\begin{itemize}
    \item Almost surely $\mu_{\hp}$ has a unique infinite cluster and $\mu^*_{\hp}$ has no infinite cluster.
    \item Almost surely $\mu^*_{\hp}$ has a unique infinite cluster and $\mu_{\hp}$ has no infinite cluster.
    \item Almost surely neither $\mu_{\hp}$ nor $\mu^*_{\hp}$ has an infinite cluster.
\end{itemize}

sketch:
To prove the main theorem, the text explains that (using Burton--Keane uniqueness) it is an immediate consequence of the following theorem, since under the hypotheses of the main theorem “the number of infinite clusters in \mu is almost surely at most $1$.”

\begin{theorem}\label{thm:main2}
Let $\mu$ be a translation-invariant, ergodic edge percolation measure on $\Z^2$ which has finitely many infinite clusters almost surely.  Then the trichotomy of \\Cref{thm:main} holds.
\end{theorem}

A proof sketch is then given for the theorem above (and hence for the main theorem): “The proof strategy for Theorem~\ref{thm:main2} has two steps.” (1) “showing that the number of infinite clusters in \mu_{\hp} is either almost surely $0$ or almost surely $1$,” with the “main challenge” being “eliminating the possibility that an infinite cluster in the full plane ‘splits’ into several infinite clusters in the half-plane.” (2) “showing that if \mu_{\hp} almost surely has a unique infinite cluster, then almost surely \mu^*_{\hp} has no infinite cluster; it suffices to show that almost surely the plaquette centered at $(1/2,1/2)$ does not connect to infinity in the dual.” The mechanism is that “almost surely both the positive $x$-axis and the negative $x$-axis connect to the unique infinite primal cluster, and these paths to infinity together ‘block’ the origin plaquette from connecting to infinity in the dual.” A “recurring technical point” throughout is “ruling out the existence of what we term ‘tenuous’ infinite clusters.”

Separately, if ergodicity is dropped, the text notes one can still deduce (by “applications of the theorem to the individual components in the ergodic decomposition of \mu”) that for $H\sim\mu_{\hp}$ the number of infinite clusters in $H$ plus the number in $H^*$ is “at most $1$,” so “$H$ and $H^*$ do not simultaneously have infinite clusters.”

theorem:
\label{main;thm;1}
	Let $3\leq n\leq 7$ and $1\leq m\leq n-2$. Let $M^n$ be a closed, orientable, connected spin manifold of dimension $n$. Let $g$ be a Riemannian metric on $M$. Let $\psi$ be a smooth function on $M$ such that	
	\[	-\Delta_M\psi -\frac{1}{2}|D_M\psi|^2 + \frac{1}{2}\Big(R_M - (n-m)(n-m-1)\Big) \geq 0.\]
Suppose that $\Phi:(M,g)\to (S^{n-m}\times \mathbb{T}^m, g_{S^{n-m}} + g_{\mathbb{T}^m})$ is a smooth map with the following properties:
	\begin{itemize}
		\item $\Phi$ has non-zero degree,
		\item $\pr_{S^{n-m}}\circ\Phi:(M,g)\to (S^{n-m}, g_{S^{n-m}})$ is area non-increasing when $n-m\geq 3$ and 1-Lipschitz when $n-m=2$.
	\end{itemize}
	Then $(M^n, g)$ is isometrically covered by $(S^{n-m}\times\mathbb{R}^m,\, g_{S^{n-m}} + g_{\mathbb{R}^m})$.,

\label{lem:anest}
Let $(M_i,g_i)$ be Riemannian manifolds of dimensions $m_i$ ($i=1,2$), and set $g=g_1\times g_2$. Then the following hold for all measurable $S\subset M_1\times M_2$ and $(m_1+m_2-1)$–rectifiable $\Sigma$:
\begin{enumerate}
\item[(i)] For every set $S \subset M_1 \times M_2$,
\begin{equation}\label{eq:anest1}
  \vv_{g_+^t}(S) = t^{m_2} \,\vv_g(S).
\end{equation}
\item[(ii)] If $\Sigma \subset M_1 \times M_2$ is $(m_1+m_2-1)$-rectifiable, then for $t \leq 1$,
\begin{equation}\label{eq:anest2}
  \hh_{g_+^t}^{m_1+m_2-1}(\Sg) 
  \leq t^{m_2-1}\,\hh_g^{m_1+m_2-1}(\Sg).
\end{equation}
\item[(iii)] Equality holds in the equation above if and only if the $g$-normal of $\Sigma$ is tangent to $M_2$, up to a $\hh_g^{m_1+m_2-1}$-null set.
\end{enumerate}

[\textbf{Dynamical stability of $n$-solitons}]\label{thm1.1}
Given $ n\in \mathbb{N} $, $ n\geq 1 $, a collection of wave speeds $\textbf{c} = (c_{1},\dots,c_{n})$ with $ 0 < c_{1} < \dots < c_{n} $ and a collection of space transitions $\textbf{x} = (x_{1},\dots,x_{n})\in \mathbb{R}^{n}$, let $ U^{(n)}(\cdot,\cdot;\textbf{c},\textbf{x}) $ be the corresponding $n$-soliton solutions of
\begin{align}
\tu_t+\frac{1}{\delta}u_x+2uu_x+T^\delta u_{xx}=0,\quad  (t,x)\in \mathbb{R} \times \mathbb{R},\label{ILW}
\end{align}
Then for any $ \epsilon > 0 $, there exists $ \delta > 0 $ such that for any $ u_{0}\in H^{\frac{n}{2}}(\mathbb{R}) $, the following stability property holds, if

\begin{align}
	&\bigl\lVert u_{0} - U^{(n)}(0,\cdot;\textbf{c},\textbf{x}) \bigr\rVert_{H^{\frac{n}{2}}} < \delta,
\end{align}
then for any $t \in \mathbb{R}$, the corresponding solution of the equation above verifies
\begin{align}
\inf_{\tau \in \mathbb{R},\  \textbf{y} \in \mathbb{R}^{n}} \bigl\lVert u(t) - U^{(n)}(\tau,\cdot;\textbf{c},\textbf{y}) \bigr\rVert_{H^{\frac{n}{2}}} < \epsilon.
\end{align}

sketch:
The proof of the main theorem proceeds by transforming the stability problem into a spectral analysis of an explicitly constructed linearized operator. Through the IST method, we establish a fundamental connection between the Hamiltonians and scattering data.

More concretely, the stated strategy is organized by sections as follows:
\begin{itemize}
\item \emph{Section~\ref{sec.2}:} establish “the properties of the singular integral operators $T^\delta$ and $T^\delta_{12}$,” and “introduce the IST framework for the ILW equation, from which the $n$-soliton solutions are formally derived.”
\item \emph{Section~\ref{sec.3}:} carry out “a detailed spectral analysis of the linearized operator $\mathcal{L}_n = \mathcal{S}_n''(U^{(n)})$,” showing “its inertia index is $\left( \left\lfloor \frac{n+1}{2} \right\rfloor, n \right)$, thereby satisfying the crucial stability condition.”
\item \emph{Section~\ref{sec.4}:} “apply the framework of constrained variational principles to establish the dynamical stability result in the main theorem.”
\end{itemize}

Additionally, the introduction notes that the orbital stability theorem
\begin{theorem}[\textbf{Orbital stability of double solitons}]\label{thm1.2}
	The double solitons $U^{(2)}_{c_1,c_2}(t,x;x_1,x_2)$ of ILW equation (\ref{ILW}) with $0<c_1<c_2$ are orbitally stable in $H^1(\mathbb{R})$ in the following sense.
There exist parameters $\epsilon_0$ and $A_0$, depending on $c_1$ and $c_2$, if there exists $\epsilon \in (0,\epsilon_0)$ such that for any $u_0\in H^1(\mathbb{R})$,
\begin{align}\label{u02}
	\bigl\lVert u_0 - U^{(2)}_{c_1,c_2}(0;0,0) \bigr\rVert_{H^1(\mathbb{R})} < \epsilon,
\end{align}
then there exist $x_1(t), x_2(t) \in \mathbb{R}$, such that the corresponding solution $u(t,x)$ of the ILW equation (\ref{ILW}) with the initial data $u(0)=u_0$ satisfies $u_t \in C([0,\infty),H^1(\mathbb{R}))$ and
\begin{align}\label{1.22}
	\sup_{t\in (0,\infty)}|\!|u(t)-U^{(2)}_{c_1,c_2}(t,x;x_1,x_2)|\!|_{H^1(\mathbb{R})}<A_0\epsilon,
\end{align}
with
\begin{align}
	\sup_{t\in (0,\infty)}(|x_1'(t)|+|x_2'(t)|)\leq CA_0\epsilon.
\end{align}
\end{theorem}

is “reduced to a detailed spectral analysis of the linearized operator $\mathcal{L}_n$ arising from the second variation of the Lyapunov functional,” and that the following theorem “relies on the application of spectral analysis results”:
\begin{theorem}[\textbf{The negative eigenvalues of $\mathcal{L}_n$}]\label{th1.3}
	The linearized operator $\mathcal{L}_{n}$ about the $n$-soliton solution possesses exactly $\left\lfloor\frac{n+1}{2}\right\rfloor$ negative eigenvalues $\lambda_{k}$, where $k=1,2,\cdots,\left\lfloor\frac{n+1}{2}\right\rfloor$ and $\lfloor x\rfloor$ denotes the floor function. Furthermore, the negative eigenvalues of $\mathcal{L}_n(n\geq 1$)  have the following expression
	\begin{align}\label{negetive}
		\lambda_{k} = -M^\delta_k (c_{2k-1}-\frac{1}{\delta})\prod_{ j\neq 2k-1}^{n}(c_{j}-c_{2k-1}),\quad k=1,2,\cdots,\left\lfloor\frac{n+1}{2}\right\rfloor,
	\end{align}
	where $M^\delta_k$ are positive constants independent of the wave speeds $c_1,\cdots, c_n$.
\end{theorem}

theorem:
Let $\kappa \geq 3$ be a cardinal. There exists a family $\{T_\kappa^{[\alpha]} : 1 \leq \alpha < \omega_1\}$ of incomplete homogenous real trees with valence $\kappa$ and a fixed isometric embedding $\psi_{\alpha,\beta}: T_\kappa^{[\alpha]} \hookrightarrow T_\kappa^{[\beta]}$ for all $\alpha < \beta$ such that:
\begin{enumerate}
    \item for any countable ordinals $\alpha, \beta$, if $\alpha \neq \beta$ then $T_\kappa^{[\alpha]}$ is not isometric to $T_\kappa^{[\beta]}$;
    \item if $\alpha < \beta < \gamma$, then $\psi_{\alpha,\gamma} = \psi_{\beta,\gamma} \circ \psi_{\alpha,\beta}$;
    \item the direct union $\cup_{\alpha < \omega_1} T_\alpha$, taken with respect to $\{\psi_{\alpha,\beta} : 1 \leq \alpha < \beta < \omega_1\}$, is isometric to the universal real tree with valence $\kappa$.
\end{enumerate}

sketch:
We ``use the description of the universal real tree $T_\kappa$ from \cite{DyubinaExplicit01} to define a filtration $T_\kappa = \cup_{\alpha < \omega_1} T_\kappa^{[\alpha]}$. \begin{definition}[Complexity] \label{def: tka}
    Given $f \in T_\kappa$, let 
